    localStorageUtil.saveDrawSettings(state);
    localStorageUtil.saveDrawFiles(files, drawId);
  };

  const onLibraryChange = (items: ImportedDataState['libraryItems']) => {
    const drawId = drawInfo?.drawId ?? 'QUICK_TRIAL';

    localStorageUtil.saveDrawLibrary(items, drawId);
  };

  const saveProgress = async () => {
    setIsLoading(true);

    const serverStorageStatus = await serverStorageUtil.save(drawInfo);

    const backdropData: IBackdropData = {
      title: 'Parece que você não está autenticado(a)...',
      bodyText: 'Por favor, crie uma conta ou realize um novo login.',
      buttonLabel: 'Fazer isso!',
      href: 'https://rabisca.io/',
      onButtonClick: () => setIsBackdropOpen(false),
      onOutsideClick: () => setIsBackdropOpen(false),
    };

    switch (serverStorageStatus) {
      case SERVER_STORAGE_VALIDATIONS.ACCESS_TOKEN_NOT_FOUND:
        setBackdropData(backdropData);
        setIsBackdropOpen(true);
        break;
      case SERVER_STORAGE_VALIDATIONS.USER_NOT_FOUND:
        setBackdropData(backdropData);
        setIsBackdropOpen(true);
        break;
      case SERVER_STORAGE_VALIDATIONS.HTTP_ERROR:
