        onOutsideClick: () => setIsBackdropOpen(false),
      });

      setIsBackdropOpen(true);
      localStorageUtil.removeLastSave();
      return;
    }

    localStorageUtil.registerLastSave();
  }, []);

  useEffect(() => {
    if (drawInfoToken) {
      const millisecondsInterval: number = Number(process.env.NEXT_PUBLIC_AUTOSAVE_SECONDS) * 1000;
      const saveEachIntervalId = setInterval(saveProgress, millisecondsInterval);

      return () => {
        clearInterval(saveEachIntervalId);
      };
    }
  }, []);

  /********************************************************************************************************************************
   *                                                        Sub-Components                                                        *
   ********************************************************************************************************************************/
  const saveButton = (isMobile: boolean) =>
    isMobile ? <></> : <Buttons.Save isLoading={isLoading} onClick={() => saveProgress()} />;

  /********************************************************************************************************************************
   *                                                        Main Component                                                        *
   ********************************************************************************************************************************/
  return (
    <div style={{ height: '100vh', width: '100vw' }} className="custom-styles">
      <Excalidraw
        ref={excalidrawRef}
        langCode="pt-BR"
        initialData={onCanvaMount()}
        renderTopRightUI={(isMobile) => saveButton(isMobile)}
        onChange={(elements, state, files) => onCanvaChange(elements, state, files)}
        onLibraryChange={(items) => onLibraryChange(items)}
      >
        <RabiscaDropdownMenu onSaveToServerClick={() => saveProgress()} />
        <RabiscaWelcomeScreen />
      </Excalidraw>
      <PopUps.Standard
        type={popUpData.type}
        message={popUpData.message}
        autoHideDuration={popUpData.duration}
        isOpen={isPopUpOpen}
        onClose={() => setIsPopUpOpen(false)}
      />
      <Backdrops.Standard
        title={backdropData.title}
        bodyText={backdropData.bodyText}
        buttonLabel={backdropData.buttonLabel}
        isOpen={isBackdropOpen}
        href={backdropData.href}
        onButtonClick={() => backdropData.onButtonClick()}
        onOutsideClick={() => backdropData.onOutsideClick()}
      />
    </div>
  );
}

