  if (state?.selectediMap?.interactivemap_locations_by_interactivemapid)
    booths = state.selectediMap.interactivemap_locations_by_interactivemapid;

  var activeBooth = state.activelyUpdatedBooth.payload;
  var toAddNewBooth = state.addEditBooth.toAddNewBooth;
  var boothToBeAdded = state.boothToAdd;

  if (activeBooth && !objectIsEmpty(activeBooth)) {
    if (toAddNewBooth) {
      let newBoothUpdated = {};
      if (!objectIsEmpty(boothToBeAdded))
        newBoothUpdated = { ...boothToBeAdded, ...activeBooth };

      boothToBeAdded = newBoothUpdated;
    } else {
      boothToBeAdded = activeBooth;
    }
  }

  return {
    session: state.session,
    booths: booths,
    Imagepath: state.selectediMap.mapfilepath,
    boothToBeAdded: boothToBeAdded,
    showmodal: state.openiMapModal.payload,
    selectedMap: state.selectediMap,
  };
}

