    suggestions.forEach(suggestion => {
      const categoryColors = {
        structure: 'rgba(29, 78, 216, 0.25)', // blue
        rhetoric: 'rgba(126, 34, 206, 0.25)', // purple  
        evidence: 'rgba(21, 128, 61, 0.25)', // green
        persuasion: 'rgba(185, 28, 28, 0.25)', // red
        style: 'rgba(67, 56, 202, 0.25)' // indigo
      };

      const color = categoryColors[suggestion.category] || 'rgba(217, 119, 6, 0.25)'; // amber fallback

      const escapeHtml = (text) => {
        return text
          .replace(/&/g, '&amp;')
          .replace(/</g, '&lt;')
          .replace(/>/g, '&gt;')
          .replace(/"/g, '&quot;')
          .replace(/'/g, '&#039;');
      };

      const issueText = suggestion.issue;
      const escapedIssue = escapeHtml(issueText);

      const patterns = [
        issueText,
        escapedIssue,
        issueText.replace(/"/g, '&quot;').replace(/'/g, '&#039;'),
        issueText.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')
      ];

      let highlighted = false;
      for (const pattern of patterns) {
        if (content.includes(pattern)) {
          content = content.replace(
            pattern,
            `<mark data-issue="${encodeURIComponent(issueText)}" style="background: linear-gradient(120deg, ${color} 0%, ${color.replace('0.25', '0.4')} 100%); padding: 3px 6px; border-radius: 4px; cursor: pointer; transition: all 0.3s; border-left: 4px solid ${color.replace('0.25', '0.8')}; font-weight: 500;" onmouseover="this.style.transform='translateY(-1px)'; this.style.boxShadow='0 4px 12px ${color.replace('0.25', '0.3')}'" onmouseout="this.style.transform='translateY(0)'; this.style.boxShadow='none'">${pattern}</mark>`
          );
          highlighted = true;
          break;
        }
      }

      if (!highlighted) {
        console.log(`Não foi possível destacar: "${issueText}" na categoria ${suggestion.category}`);
      }
    });

    editorRef.current.innerHTML = content;
  };

