      const parent = mark.parentElement;
      if (parent?.style.fontSize) span.style.fontSize = parent.style.fontSize;
      if (parent?.style.fontFamily) span.style.fontFamily = parent.style.fontFamily;
      mark.parentNode.replaceChild(span, mark);
