function pageBreak() {
  return new Paragraph({ children: [new PageBreak()] });
}

function divider() {
  return new Paragraph({
    border: { bottom: { style: BorderStyle.SINGLE, size: 6, color: "2E75B6", space: 1 } },
    spacing: { before: 100, after: 100 },
    children: []
  });
}

function chapterTitle(num, title, subtitle) {
  return [
    pageBreak(),
    new Paragraph({
      spacing: { before: 200, after: 80 },
      children: [
        new TextRun({ text: `BAB ${num}`, bold: true, size: 28, color: "AAAAAA", font: "Arial" })
      ]
    }),
    new Paragraph({
      spacing: { before: 0, after: 120 },
      children: [
        new TextRun({ text: title, bold: true, size: 38, color: "1F4E79", font: "Arial" })
      ]
    }),
    new Paragraph({
      spacing: { before: 0, after: 300 },
      children: [
        new TextRun({ text: subtitle, size: 24, color: "555555", font: "Arial", italics: true })
      ]
    }),
    divider()
  ];
}

