export default function DeptAIPlatform() {
  const [activeDept, setActiveDept] = useState(DEPARTMENTS[0]);
  const [chats, setChats] = useState({});
  const [input, setInput] = useState("");
  const [loading, setLoading] = useState(false);
  const [sidebarOpen, setSidebarOpen] = useState(true);
  const bottomRef = useRef(null);
  const inputRef = useRef(null);

  const currentMessages = chats[activeDept.id] || [];

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [chats, loading]);

  useEffect(() => {
    inputRef.current?.focus();
  }, [activeDept]);

  const sendMessage = async () => {
    if (!input.trim() || loading) return;
    const userMsg = { role: "user", content: input.trim() };
    const updatedMsgs = [...currentMessages, userMsg];
    setChats(prev => ({ ...prev, [activeDept.id]: updatedMsgs }));
    setInput("");
    setLoading(true);

    try {
      const res = await fetch("https://api.anthropic.com/v1/messages", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          model: "claude-sonnet-4-20250514",
          max_tokens: 1000,
          system: activeDept.systemPrompt,
          messages: updatedMsgs.map(m => ({ role: m.role, content: m.content }))
        })
      });
      const data = await res.json();
      const reply = data.content?.[0]?.text || "Sorry, I couldn't generate a response.";
      setChats(prev => ({
        ...prev,
        [activeDept.id]: [...updatedMsgs, { role: "assistant", content: reply }]
      }));
    } catch {
      setChats(prev => ({
        ...prev,
        [activeDept.id]: [...updatedMsgs, { role: "assistant", content: "Something went wrong. Please try again." }]
      }));
    }
    setLoading(false);
  };

  const clearChat = () => setChats(prev => ({ ...prev, [activeDept.id]: [] }));

  const handleKey = e => {
    if (e.key === "Enter" && !e.shiftKey) { e.preventDefault(); sendMessage(); }
  };

  const switchDept = dept => {
    setActiveDept(dept);
    setSidebarOpen(window.innerWidth > 640);
  };

