        .dept-item:hover { background: #1e293b; }
        .send-btn { transition: all 0.15s; }
        .send-btn:hover:not(:disabled) { transform: scale(1.05); }
        .send-btn:disabled { opacity: 0.4; cursor: not-allowed; }
        .starter-btn { transition: all 0.15s; border: 1px solid #1e293b; background: #0f172a; border-radius: 8px; padding: 8px 12px; font-size: 12px; color: #94a3b8; cursor: pointer; text-align: left; }
        .starter-btn:hover { border-color: var(--dept-color); color: #e2e8f0; background: #1e293b; }
